268→private fun ASTNode.replaceWhitespaceWith(text: String) {
269→    require(this.elementType == WHITE_SPACE)
270→    if (this.text != text) {
271→        (this.psi as LeafElement).rawReplaceWithText(text)
272→    }
273→}
