294→        when (val nextSibling = nextSibling()) {
295→            null -> {
296→                // Never insert a whitespace element as last child node in a composite node. Instead, upsert just after the composite node
297→                treeParent.upsertWhitespaceAfterMe(text)
298→            }
299→
300→            is LeafElement -> {
