314→public val ASTNode.column: Int
315→    get() {
316→        var leaf = this.prevLeaf()
317→        var offsetToTheLeft = 0
318→        while (leaf != null) {
319→            if ((leaf.elementType == WHITE_SPACE || leaf.elementType == REGULAR_STRING_PART) && leaf.textContains('\n')) {
320→                offsetToTheLeft += leaf.textLength - 1 - leaf.text.lastIndexOf('\n')
321→                break
322→            }
323→            offsetToTheLeft += leaf.textLength
324→            leaf = leaf.prevLeaf()
325→        }
326→        return offsetToTheLeft + 1
327→    }
