386→/**
387→ * Creates a sequence of leaf nodes in the open range [from] - [to]. This means that the boundary nodes are excluded
388→ * from the range in case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first
389→ * leaf node in the sequence is the first leaf node in this [CompositeElement]. In case [to] is a [CompositeElement]
390→ * than the last node in the sequence is the last leaf node prior to this [CompositeElement].
391→ */
392→public fun leavesInOpenRange(
393→    from: ASTNode,
394→    to: ASTNode,
395→): Sequence<ASTNode> =
396→    from
397→        .leaves()
398→        .takeWhile { it != to && it != to.lastChildLeafOrSelf() }
399→
400→/**
401→ * Creates a sequence of leaf nodes in the closed range [from] - [to]. This means that the boundary nodes are included from the range in
402→ * case they would happen to be a leaf node. In case [from] is a [CompositeElement] than the first leaf node in the sequence is the first
403→ * leaf node in this [CompositeElement]. In case [to] is a [CompositeElement] than the last node in the sequence is the last leaf node of
404→ * this [CompositeElement].
405→ */
406→public fun leavesInClosedRange(
407→    from: ASTNode,
408→    to: ASTNode,
409→): Sequence<ASTNode> {
410→    val stopAtLeaf =
411→        to
412→            .lastChildLeafOrSelf()
413→            .nextLeaf()
414→    return from
415→        .firstChildLeafOrSelf()
416→        .leavesIncludingSelf()
417→        .takeWhile { it != stopAtLeaf }
418→}
