422→/**
423→ * Creates a sequences of leaves including the [ASTNode] in case it is a [LeafElement] itself. By default, the leaves are traversed in
424→ * forward order. Setting [forward] to `false` changes this to traversal in backward direction.
425→ */
426→public fun ASTNode.leavesIncludingSelf(forward: Boolean = true): Sequence<ASTNode> {
427→    val sequence =
428→        if (isLeaf()) {
429→            sequenceOf(this)
430→        } else {
431→            emptySequence()
432→        }
433→    return sequence.plus(leaves(forward))
434→}
