436→/**
437→ * Get all leaves on the same line as the given node including the whitespace indentation. Note that the whitespace indentation may start
438→ * with zero or more newline characters.
439→ */
440→public fun ASTNode.leavesOnLine(): Sequence<ASTNode> {
441→    val lastLeafOnLineOrNull = getLastLeafOnLineOrNull()
442→    return getFirstLeafOnLineOrSelf()
443→        .leavesIncludingSelf()
444→        .takeWhile { lastLeafOnLineOrNull == null || it.prevLeaf() != lastLeafOnLineOrNull }
445→}
