455→public fun ASTNode.lineLengthWithoutNewlinePrefix(): Int =
456→    leavesOnLine()
457→        .joinToString(separator = "") { it.text }
458→        // If a line is preceded by a blank line then the ident contains multiple newline chars
459→        .dropWhile { it == '\n' }
460→        // In case the last element on the line would contain a newline then only include chars before that newline. Note that this should
461→        // not occur if the AST is parsed correctly
462→        .takeWhile { it != '\n' }
463→        .length
